//! SBI call wrappers

#![allow(unused)]

use core::arch::asm;
/// set timer sbi call id
const SBI_SET_TIMER: usize = 0;
/// console putchar sbi call id
const SBI_CONSOLE_PUTCHAR: usize = 1;
/// console getchar sbi call id
const SBI_CONSOLE_GETCHAR: usize = 2;
/// shutdown sbi call id
const SBI_SHUTDOWN: usize = 8;
const UART0: usize = 0x1000_0000;
const UART_REG_THR: usize = 0;
const UART_REG_RBR: usize = 0;
const UART_REG_LSR: usize = 5;
const UART_LSR_DR: u8 = 1;
const UART_LSR_THRE: u8 = 1 << 5;

/// general sbi call
#[inline(always)]
fn sbi_call(which: usize, arg0: usize, arg1: usize, arg2: usize) -> usize {
    let mut ret;
    unsafe {
        asm!(
            "ecall",     // sbi call
            inlateout("x10") arg0 => ret, // sbi call arg0 and return value
            in("x11") arg1, // sbi call arg1
            in("x12") arg2, // sbi call arg2
            in("x16") 0, // for sbi call id args need 2 reg (x16, x17)
            in("x17") which,// sbi call id
        );
    }
    ret
}

/// use sbi call to set timer
pub fn set_timer(timer: usize) {
    sbi_call(SBI_SET_TIMER, timer, 0, 0);
}

/// use sbi call to putchar in console (qemu uart handler)
pub fn console_putchar(c: usize) {
    // SAFETY: UART0 is mapped as MMIO in the kernel address space on QEMU virt.
    // The transmit holding register is written only after the line status
    // register reports it is empty.
    unsafe {
        while ((UART0 + UART_REG_LSR) as *const u8).read_volatile() & UART_LSR_THRE == 0 {}
        ((UART0 + UART_REG_THR) as *mut u8).write_volatile(c as u8);
    }
}

/// use sbi call to getchar from console (qemu uart handler)
pub fn console_getchar() -> usize {
    // SAFETY: UART0 is mapped as MMIO in the kernel address space on QEMU virt.
    // The line status register is read-only and the receiver buffer register is
    // read only when UART_LSR_DR indicates that one byte is available.
    unsafe {
        let lsr = ((UART0 + UART_REG_LSR) as *const u8).read_volatile();
        if lsr & UART_LSR_DR == 0 {
            return usize::MAX;
        }
        ((UART0 + UART_REG_RBR) as *const u8).read_volatile() as usize
    }
}

/// use sbi call to shutdown the kernel
pub fn shutdown() -> ! {
    sbi_call(SBI_SHUTDOWN, 0, 0, 0);
    panic!("It should shutdown!");
}

